def load(runtime):
    subscripts_path = Path(__file__).resolve().parent
    for module_filename in MODULE_FILENAMES:
        module_path = subscripts_path / module_filename
        spec = importlib.util.spec_from_file_location(
            module_path.stem,
            module_path,
        )
        if spec is None or spec.loader is None:
            raise ImportError(
                f"Subscript konnte nicht geladen werden: {module_path}"
            )
        module = importlib.util.module_from_spec(spec)
        spec.loader.exec_module(module)
        module.register(runtime)
